{
  "summary": "This paper proposes Contrastive Novelty Learning (CNL), a method for open-set selective classification in text by generating semantically novel class examples using large language models and training classifiers with a contrastive confidence loss to reduce overconfidence on novel inputs. Extensive experiments demonstrate improved selective prediction and out-of-distribution detection performance without sacrificing in-distribution accuracy across multiple NLP datasets.",
  "strengths": [
    {
      "point": "Innovative use of large language models to generate semantically novel labels and examples for open-set classification.",
      "evidence": "Novelty Prompting uses GPT-3 Davinci and GPT-J 6B to generate novel class labels and corresponding examples, improving OOD detection and selective classification."
    },
    {
      "point": "Contrastive Confidence Loss (CCL) effectively reduces confidence on novel examples without harming in-distribution accuracy.",
      "evidence": "CCL penalizes only when novel examples have higher confidence than ID examples, outperforming Outlier Exposure which often reduces ID accuracy."
    },
    {
      "point": "Comprehensive empirical evaluation across 14 dataset splits and multiple baselines showing consistent improvements.",
      "evidence": "CNL improves AUAC by 2.3% and AUROC by 5.5% over strong baselines including contrastive training and kFolden ensembles."
    },
    {
      "point": "Robustness and generalizability demonstrated across different classifier architectures and varying generation budgets.",
      "evidence": "Performance gains hold for BERT-base, RoBERTa-base, RoBERTa-large, and with smaller LLMs and fewer generated examples."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent state-of-the-art OOD detection methods specific to NLP.",
      "evidence": "No evaluation against energy-based models or Mahalanobis distance-based detectors limits claims of superiority."
    },
    {
      "point": "Insufficient justification for the choice of two different LLMs for label and example generation.",
      "evidence": "No analysis on why GPT-3 Davinci and GPT-J 6B were chosen or whether a single model could suffice."
    },
    {
      "point": "Missing ablation on the filtering step that removes synonyms or related labels to ensure novelty.",
      "evidence": "No sensitivity analysis on how imperfect filtering affects performance despite its centrality to the approach."
    },
    {
      "point": "Evaluation metrics limited to AUAC and AUROC without reporting calibration or detection quality metrics.",
      "evidence": "No F1-score for novel class detection or Expected Calibration Error reported to assess confidence quality."
    },
    {
      "point": "Reproducibility concerns due to missing prompt templates, hyperparameters, and random seed reporting.",
      "evidence": "Details on prompt design, training hyperparameters, and variance across runs are not provided."
    },
    {
      "point": "Ambiguity in the definition of 'novel class' examples and lack of human evaluation of generated examples.",
      "evidence": "Unclear if novel classes are disjoint or semantically overlapping with ID classes; no human verification of novelty or plausibility."
    },
    {
      "point": "Limited generalizability beyond text classification and synthetic novel classes.",
      "evidence": "No experiments on other NLP tasks or real-world unseen novel classes to validate broader applicability."
    },
    {
      "point": "No discussion on scalability to large label sets or potential failure modes with low-quality generated examples.",
      "evidence": "Scalability and robustness to noisy or misleading generated data are not analyzed in depth."
    }
  ],
  "questions": [
    {
      "question": "How does CNL compare to recent NLP-specific OOD detection methods like energy-based or Mahalanobis detectors?",
      "motivation": "To establish the method's relative effectiveness against the current state-of-the-art."
    },
    {
      "question": "What is the impact of imperfect filtering of generated labels on the novelty and overall performance?",
      "motivation": "Filtering is critical to ensure semantic novelty; understanding sensitivity is important for robustness."
    },
    {
      "question": "Can the approach scale effectively to tasks with very large or hierarchical label sets common in real-world applications?",
      "motivation": "Scalability is essential for practical deployment in diverse NLP scenarios."
    },
    {
      "question": "How well does CNL perform on genuinely unseen, real-world novel classes rather than synthetic ones generated by LLMs?",
      "motivation": "To assess practical utility and generalization beyond synthetic benchmarks."
    },
    {
      "question": "Would a single large LLM suffice for both label and example generation, and how does model choice affect results?",
      "motivation": "To simplify the pipeline and understand the contribution of model architecture and size."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
